var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"......제이나!!","JPN":"……ジェイナ！！","ENG":"Jaina!","TWN":"……婕娜！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제이나! 정신이 드나!","JPN":"ジェイナ！　気がついたか？","ENG":"Jaina! Wake up!","TWN":"婕娜！你清醒了嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님......?","JPN":"副司令官……？","ENG":"Deputy Commander?","TWN":"副司令官大人……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"훗...... 지금까지 봐온 망상들 중에 제일 생생한걸.","JPN":"フッ……これまで見てきた妄想の中でも、一番生々しい。","ENG":"Heh... It's the most vivid delusion I've ever seen.","TWN":"呵呵……這是我至目前為止所幻想出最栩栩如生的一次了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"나도 아직 미련이 많이 남아있었나 보네.","JPN":"私にもまだ未練が残っていたのか。","ENG":"I guess I still have a lot of regrets.","TWN":"看來我還有很多留戀啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......망상이 아니다.","JPN":"……妄想ではない。","ENG":"I'm not a delusion.","TWN":"……不是幻想。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"나다, 도미닉 킹 레지날드.","JPN":"私だ、ドミニーク・キング・レジナルド。","ENG":"It's me, Dominic King Reginald.","TWN":"是我，多明尼克·金·雷吉納德。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"촌구석 교회에 숨어 있던 널 구해준 사람이지.","JPN":"教会に隠れていたお前を救った人間だ。","ENG":"I'm the person who saved you in that village church.","TWN":"把躲在村莊角落教會的你救出來的人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 지금 다시 한 번 더 널 구하러 왔다. 그러니 정신 차려라.","JPN":"そして、今再びお前を助けに来た。だからしっかりしろ。","ENG":"And I'm here to save you once again. So wake up.","TWN":"現在我又一次來救你了。所以快清醒過來吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"진짜......","JPN":"本当に……","ENG":"You...","TWN":"真的……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"진짜 레지날드 부사령관님인가요?","JPN":"本当にレジナルド副司令官ですか？","ENG":"You're the real Deputy Commander Reginald?","TWN":"真的是多明尼克副司令官嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"아니, 그럴리가...... 부사령관님이 어떻게 이곳에 오신 거죠?","JPN":"いや、そんなはずが……副司令官がどうしてここにいらっしゃるんですか？","ENG":"No, that can't be... How can you be here?","TWN":"不、不可能……副司令官大人怎麼會來這裡？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"이곳은 차원함선으로도 도달할 수 없는 곳인데......","JPN":"ここは次元艦船でも到達できない場所なのに.......","ENG":"Even a dimensional ship can't reach this place...","TWN":"這裡是次元戰艦也無法到達的地方……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......모종의 조력자가 있었다.","JPN":"……協力者がいた。","ENG":"I had some help.","TWN":"……我有某種意義上的幫手。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"모두 이야기하자면 길어, 일단 여기에서 빠져나가도록 하지.","JPN":"話せば長い、とりあえずここから抜け出そう。","ENG":"It's a long story. Let's get out of here first.","TWN":"說來話長，先從這裡出去吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"하, 하지만 전 차원통로를 통과하면서 하반신이 네임리스 원의 육체에 파묻혀 버렸습니다.","JPN":"で、ですが、私は次元通路を通過した時、下半身がネームレスワンの身体に埋もれてしまいました。","ENG":"B-but my lower torso was buried inside the Nameless One's body as we passed through the dimensional passage.","TWN":"但、但是我通過次元通道的時候，下半身被無名1的肉身壓住了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"아무리 힘을 써도 움직일 수가 없었어요.","JPN":"いくら力を振り絞っても動けませんでした。","ENG":"No matter how hard I try, I can't free myself.","TWN":"無論我怎麼用力都不能動彈。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그래 보이는군.","JPN":"そのようだな。","ENG":"It looks like it.","TWN":"好像是這樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내가 꺼내주지. 눈을 감고, 조금만 참아라.","JPN":"私が出してやる。目を閉じて、少しだけ耐えろ。","ENG":"I'll get you out of there. Close your eyes, and hang in there.","TWN":"我會把你弄出來，閉上眼，忍耐一下。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"네? 아무리 부사령관님이라고 해도 네임리스 원의 육체를 파괴하는 건 무리입니다!","JPN":"はい？　いくら副司令官でも、ネームレスワンの肉体を破壊することは無理です！","ENG":"Huh? Even for you, Deputy Commander, it's impossible to destroy the Nameless One's body!","TWN":"啊？就算是副司令官大人您，也沒辦法破壞無名1的肉身啊！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그건 해봐야 알 일이다.","JPN":"それはやってみないとわからない。","ENG":"You don't know until you try.","TWN":"要試一試才知道。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"충격에 주의하도록!","JPN":"衝撃に備えろ！","ENG":"Brace yourself for impact!","TWN":"注意衝擊！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"쿨럭! 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":"*Cough, cough*","TWN":"咳咳！咳咳！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"저, 정말로 빠져 나왔어?","JPN":"ほ、本当に抜け出せた？","ENG":"I-I really got out?","TWN":"真、真的出來了？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"어떻게......? 설마 그 사이에 이 정도로 강해지신 건가요?","JPN":"どうやって……？　お会いしていない間に、さらに強くなられたのですか？","ENG":"How? Have you become stronger?","TWN":"怎麼可能……？難道這段時間您變得這麼強了？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 내가 강해졌다기 보다는 이 녀석이 약해진 것 같군.","JPN":"いや、私が強くなったというよりも、こいつが弱くなったようだ。","ENG":"No, the Nameless One is weaker now.","TWN":"不，與其說我變強了不如說這傢伙變弱了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"애초에 모양도...... 내가 알던 네임리스 원이 아니야.","JPN":"そもそも見た目も……私が知っているネームレスワンではない。","ENG":"And it's not the same shape as I remember.","TWN":"連樣子……也跟我最開始看到的無名1不同。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그러고 보니 이건 마치...... 고치 같군요.","JPN":"言われてみればこれはまるで……繭のようですね。","ENG":"Now that you mention it... it looks like a cocoon.","TWN":"這麼說的話，這個看起來確實像是……一個卵囊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"처음 본다는 말투로군. 이 녀석이 왜 이렇게 변했는지 아는 바가 없나?","JPN":"初めて見たような言いぶりだな。こいつがどうして変わったのか知らないのか？","ENG":"You talk like you've never seen it before. Do you have any idea why it changed?","TWN":"看來你是第一次見的樣子。難道你不知道這傢伙為什麼會變成這樣嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"차원 통로로 떨어진 직후에 전 정신을 잃었습니다.","JPN":"次元通路に落ちた直後に私は気を失いました。","ENG":"I lost consciousness right after I fell into the dimensional passage.","TWN":"從次元通道墜落後我就失去了意識。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그 동안 시간이 얼마나 지났는지도 모르겠어요.","JPN":"あれから時間がどれくらい経ったのかもわかりません。","ENG":"I don't even know how much time has passed since then.","TWN":"也不知道過了多長時間。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그러고 보니 얼마나 지났죠?","JPN":"そういえば、どれぐらい過ぎているのですか？","ENG":"Speaking of which, how long have I been here?","TWN":"話說回來，過去多久了？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......널 잊을 정도는 아니었다고 해두지.","JPN":"……お前のことを忘れるほどではないと言っておこう。","ENG":"...Not long enough for me to forget you.","TWN":"……還沒久到忘記你的程度。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그보다 저 녀석, 움직이기 시작하는군.","JPN":"それよりもあいつ、動き出したな。","ENG":"By the way, it looks like that thing is starting to move.","TWN":"不過這傢伙，開始動起來了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_05"},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"네? 설마......?","JPN":"え？　まさか……？","ENG":"Huh? No way!","TWN":"啊？莫非……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"제, 제가 시간을 벌겠습니다!","JPN":"わ、私が時間を稼ぎます！","ENG":"I-I'll stall for time!","TWN":"我、我來爭取時間！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"여긴 제게 맡기시고 빨리 도망치세요 부사령관님!","JPN":"ここは私に任せて、はやくお逃げください、副司令官！","ENG":"Leave this to me and get to safety, Deputy Commander!","TWN":"這裡交給我，你先逃走吧。副司令官大人！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"네임리스 원이 다시 활성화 되면 우리 둘로는 막을 수가 없어요.","JPN":"ネームレスワンがまた活性化したら、私たち二人だけでは止められません！","ENG":"If the Nameless One wakes up again, we won't be able to match for it.","TWN":"如果無名1復活，靠我們兩個人沒辦法對付它。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 널 눈앞에서 잃는 건 한 번이면 족하다.","JPN":"いや、目の前でお前を失うのは一度で十分だ。","ENG":"No, I'm not going to lose you before my eyes again.","TWN":"不，失去你一次就已經足夠了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이번에야 말로 저 괴물과 결판을 내겠어.","JPN":"今度こそ、あの化け物と決着をつけてやる。","ENG":"This time, I'll have it out with that monster.","TWN":"這次我要跟這傢伙決一勝負。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그게 가능할 리가 없잖습니까!","JPN":"無茶です！","ENG":"That's impossible!","TWN":"但那是不可能贏的啊!"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"북극점 공방전에서도 놈을 막기 위해 그 많은 희생을 무릅썼는데......","JPN":"北極点攻防戦でも、奴を止めるためにあれほど多くの犠牲を払ったのに……","ENG":"Don't you remember how many men we lost during the North Pole Battle stopping that monster?","TWN":"在北極點攻防戰中為了擋住它，我們犧牲了那麼多人……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 다시 놈을 잘 살펴보도록.","JPN":"違う、もう一度奴をしっかり見てみろ。","ENG":"No, take a better look at it.","TWN":"不，先觀察它。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저 고치는 분명 네임리스 원이 변해서 만들어진 것이지만 그때만큼 강하지는 않아.","JPN":"あの繭はおそらくネームレスワンが変形したものではあるが、あの時ほど強くはない。","ENG":"That cocoon is definitely made from the Nameless One's body, but it's not as strong as before.","TWN":"那個卵囊明顯是無名1變成的，但它應該沒有以前那麼強。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"가지고 있던 힘을 대체 어디에 소모했는지는 몰라도 저건 더 이상 공포스러운 5종 침식체가 아니다.","JPN":"持っていた力をいったいどうしたのかは不明だが、あれはもう恐るべき第5種侵食体ではない。","ENG":"I don't know how it consumed all its energy, but it's no longer the fearful Category 5 C.O. we used to know.","TWN":"雖然不知道它把力量消耗在了哪裡，但它已經不是恐怖的5類侵蝕體了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"지금이라면 쓰러트릴 수 있어!","JPN":"今なら倒せる！","ENG":"We can defeat it now!","TWN":"現在，我們可以打敗它！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님의 말이 맞다고 해도 최소 4종 침식체 급의 괴물일 겁니다!","JPN":"副司令官の言うとおりだとしても、最低でも第4種侵食体レベルの化け物です！","ENG":"Even if you're correct, that thing is still as powerful as a Category 4 C.O.!","TWN":"就算副司令官大人說的沒錯，可它至少也是4類侵蝕體級別的怪物吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"대체...... 대체 왜 이런 위험을 무릅쓰시는 거죠?","JPN":"なぜ……なぜこれほどの危険を冒すのですか？","ENG":"Why... Why are you taking such a risk?","TWN":"到底…… 到底為什麼要冒著這樣的危險？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님은 현실주의자이지 않습니까?","JPN":"副司令官は現実主義者ではありませんか？","ENG":"Aren't you a realist?","TWN":"副司令官大人不是現實主義者嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 의무를 지키는 자이기도 하다.","JPN":"そして義務を守る者でもある。","ENG":"I'm also a man of duty.","TWN":"我有我必須堅守住的義務。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내겐, 전우를 지킬 의무가 있어.","JPN":"私には、戦友を守る義務がある。","ENG":"I have a duty to protect my comrades.","TWN":"我有，保護戰友的義務。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_RECRUITMNET_LIGHTNING"},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};